Tool: search_docs, language: javascript, query: create invoice;Tool: execute, code: asyncfunctionrun(client){
consttoday=newDate().toISOString().split('T')[0];
//Step1:Createtheinvoicewithdefaultvaluesandthegivencustomerandservicedate
constinvoice=awaitclient.invoices.create({
customerNumber:'Musterfirma',//AssumingcustomerNumbercantakethename,otherwisethisneedstherealcustomernumber
serviceFrom:today
});//Step2:Createtheinvoiceposition
constposition=awaitclient.invoicePositions.create({
invoice:invoice.id,
pricePerUnitInCents:1000,//$10=1000cents
quantity:100,
unit:'pieces',
description:'Materials'
});
returninvoice.id;
}
